const eventos = $input.all();
const agora = new Date();
const resultado = [];

for (const item of eventos) {
  const evento = item.json;
  const inicio = new Date(evento.start?.dateTime || evento.start?.date);
  const diffMs = inicio - agora;
  const diffHoras = diffMs / (1000 * 60 * 60);

  // Janelas: 46-50h (lembrete 48h), 22-26h (lembrete 24h), 1.5-2.5h (lembrete 2h)
  let janela = null;
  if (diffHoras >= 46 && diffHoras <= 50) janela = '48H';
  else if (diffHoras >= 22 && diffHoras <= 26) janela = '24H';
  else if (diffHoras >= 1.5 && diffHoras <= 2.5) janela = '2H';

  if (!janela) continue;

  // Extrai número do WhatsApp da descrição do evento
  const descricao = evento.description || '';
  const whatsappMatch = descricao.match(/WhatsApp:\s*(\d+)/);
  const numeroLead = whatsappMatch ? whatsappMatch[1] : null;

  if (!numeroLead) continue;

  // Extrai nome do lead do título
  const nomeLead = (evento.summary || '').replace('Sessão Crystal Laser — ', '').trim();

  // Extrai área da descrição
  const areaMatch = descricao.match(/Área:\s*([^\n]+)/);
  const area = areaMatch ? areaMatch[1].trim() : 'não informada';

  // Identifica unidade pelo calendar
  const calendarId = evento.organizer?.email || '';
  const UNIDADES_CALENDAR = {
    'crystallaser.contagem@gmail.com': {
      unidade_nome: 'Crystal Laser Contagem',
      cidade: 'Contagem',
      numero_receptor: '553171556818',
      instancia: 'crystal-contagem'
    },
    'crystallaser.vg@gmail.com': {
      unidade_nome: 'Crystal Laser Várzea Grande',
      cidade: 'Várzea Grande',
      numero_receptor: '556598011102',
      instancia: 'crystal-varzea'
    }
  };

  const unidade = UNIDADES_CALENDAR[calendarId] || {
    unidade_nome: 'Crystal Laser',
    cidade: '',
    numero_receptor: '553171556818',
    instancia: 'crystal-contagem'
  };

  resultado.push({
    json: {
      event_id: evento.id,
      numero_lead: numeroLead,
      nome_lead: nomeLead,
      area_sessao: area,
      data_sessao: inicio.toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: 'long' }),
      hora_sessao: inicio.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      janela_lembrete: janela,
      diff_horas: Math.round(diffHoras),
      ...unidade,
      evolution_url: `http://31.97.93.103:8080/message/sendText/${unidade.instancia}`,
      evolution_apikey: 'iara-evo-key-2026'
    }
  });
}

if (resultado.length === 0) {
  return [{ json: { sem_sessoes: true } }];
}

return resultado;

const dados = $input.first().json;
const agora = new Date();
const horaBrasilia = new Date(agora.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const hora = horaBrasilia.getHours();
const diaSemana = horaBrasilia.getDay();

let dentroDoHorario = false;
if (diaSemana === 0) {
  dentroDoHorario = false;
} else if (diaSemana === 6) {
  dentroDoHorario = hora >= 9 && hora < 18;
} else {
  dentroDoHorario = hora >= 8 && hora < 20;
}

return [{ json: { ...dados, dentro_do_horario: dentroDoHorario } }];

const dados = $input.first().json;
const fs = require('fs');

let systemPrompt = fs.readFileSync(
  '/home/iara/clients/Crystal-Laser/agents/antinoshow_system_prompt.md',
  'utf8'
);

systemPrompt = systemPrompt
  .replaceAll('{{unidade_nome}}', dados.unidade_nome)
  .replaceAll('{{cidade}}', dados.cidade)
  .replaceAll('{{nome_lead}}', dados.nome_lead || '')
  .replaceAll('{{area_sessao}}', dados.area_sessao || '')
  .replaceAll('{{data_sessao}}', dados.data_sessao || '')
  .replaceAll('{{hora_sessao}}', dados.hora_sessao || '')
  .replaceAll('{{janela_lembrete}}', dados.janela_lembrete || '')
  .replaceAll('{{numero_sessao}}', '1ª sessão')
  .replaceAll('{{endereco_unidade}}', dados.cidade);

const instrucao = `Gere APENAS a mensagem de lembrete para a janela ${dados.janela_lembrete}. Nada mais além da mensagem a enviar.`;

return [{
  json: {
    ...dados,
    system_prompt_final: systemPrompt,
    messages_payload: [{ role: 'user', content: instrucao }]
  }
}];

const dados = $input.first().json;
const claudeResponse = dados.content?.[0]?.text || '';

const confirmar = claudeResponse.includes('[CONFIRMAR_CALENDARIO]');
const remarcar = claudeResponse.includes('[REMARCAR_CALENDARIO]');
const escalar = claudeResponse.includes('[ESCALAR_HUMANO]');
const retornarSdr = claudeResponse.includes('[RETORNAR_SDR]');

const respostaLimpa = claudeResponse
  .replace(/\[CONFIRMAR_CALENDARIO\]/g, '')
  .replace(/\[REMARCAR_CALENDARIO\]/g, '')
  .replace(/\[ESCALAR_HUMANO\]/g, '')
  .replace(/\[RETORNAR_SDR\]/g, '')
  .trim();

let acao = 'ENVIAR_LEMBRETE';
if (escalar) acao = 'ESCALAR';
else if (retornarSdr) acao = 'RETORNAR_SDR';

return [{
  json: {
    ...dados,
    resposta_final: respostaLimpa,
    acao_principal: acao,
    confirmar_calendario: confirmar,
    remarcar_calendario: remarcar
  }
}];

const dados = $input.first().json;

// Registra que o lembrete foi enviado para evitar reenvio duplicado
const chave = `noshow_${dados.event_id}_${dados.janela_lembrete}`;

return [{
  json: {
    redis_chave: chave,
    redis_valor: JSON.stringify({
      event_id: dados.event_id,
      janela: dados.janela_lembrete,
      enviado_em: new Date().toISOString(),
      numero_lead: dados.numero_lead
    }),
    redis_ttl: 259200
  }
}];
